{
    "itemId": "example-tagged",
    "itemType": "scope",
    "metadata": {
        "id": "example-tagged",
        "name": "Tagged Example Scope",
        "description": "A scope with tags for organization",
        "scope": "systemscope",
        "tags": ["production", "ecommerce"],
        "enabled": true
    }
}

{
    "itemId": "{{scopeId}}",
    "itemType": "scope",
    "metadata": {
        "id": "{{scopeId}}",
        "name": "Updated Scope Name",
        "description": "Updated description for the scope",
        "scope": "systemscope",
        "enabled": true
    }
}

{
    "metadata": {
        "id": "active-premium-users",
        "name": "Active Premium Users",
        "scope": "{{scope}}",
        "description": "Premium users who are active"
    },
    "condition": {
        "type": "booleanCondition",
        "parameterValues": {
            "operator": "and",
            "subConditions": [
                {
                    "type": "profilePropertyCondition",
                    "parameterValues": {
                        "propertyName": "properties.subscriptionType",
                        "comparisonOperator": "equals",
                        "propertyValue": "premium"
                    }
                },
                {
                    "type": "profilePropertyCondition",
                    "parameterValues": {
                        "propertyName": "properties.isActive",
                        "comparisonOperator": "equals",
                        "propertyValueBoolean": true
                    }
                }
            ]
        }
    }
}

{
    "metadata": {
        "id": "active-users",
        "name": "Active Users",
        "scope": "{{scope}}",
        "description": "Users who viewed pages in the last 30 days"
    },
    "condition": {
        "type": "pastEventCondition",
        "parameterValues": {
            "eventType": "view",
            "numberOfDays": 30,
            "minimumEventCount": 1
        }
    }
}

{
    "metadata": {
        "id": "engaged-customers",
        "name": "Engaged Customers",
        "scope": "{{scope}}",
        "description": "Users who viewed pages recently and made purchases"
    },
    "condition": {
        "type": "booleanCondition",
        "parameterValues": {
            "operator": "and",
            "subConditions": [
                {
                    "type": "pastEventCondition",
                    "parameterValues": {
                        "eventType": "view",
                        "numberOfDays": 30,
                        "minimumEventCount": 10
                    }
                },
                {
                    "type": "pastEventCondition",
                    "parameterValues": {
                        "eventType": "purchase",
                        "numberOfDays": 90,
                        "minimumEventCount": 1
                    }
                }
            ]
        }
    }
}

{
    "metadata": {
        "id": "vip-premium-users",
        "name": "VIP Premium Users",
        "scope": "{{scope}}",
        "description": "Users who are in premium segment and have VIP status"
    },
    "condition": {
        "type": "booleanCondition",
        "parameterValues": {
            "operator": "and",
            "subConditions": [
                {
                    "type": "profileSegmentCondition",
                    "parameterValues": {
                        "segments": ["premium-users"]
                    }
                },
                {
                    "type": "profilePropertyCondition",
                    "parameterValues": {
                        "propertyName": "properties.vipStatus",
                        "comparisonOperator": "equals",
                        "propertyValue": "active"
                    }
                }
            ]
        }
    }
}

{
    "metadata": {
        "id": "set-premium-on-purchase",
        "name": "Set Premium on Purchase",
        "description": "Set premium flag when user makes a purchase",
        "scope": "{{scope}}",
        "enabled": true
    },
    "condition": {
        "type": "eventTypeCondition",
        "parameterValues": {
            "eventTypeId": "purchase"
        }
    },
    "actions": [
        {
            "type": "setPropertyAction",
            "parameterValues": {
                "setPropertyName": "properties.isPremium",
                "setPropertyValue": true
            }
        }
    ]
}

{
    "metadata": {
        "id": "add-to-premium-segment",
        "name": "Add to Premium Segment",
        "description": "Add profile to premium segment on purchase",
        "scope": "{{scope}}",
        "enabled": true
    },
    "condition": {
        "type": "booleanCondition",
        "parameterValues": {
            "operator": "and",
            "subConditions": [
                {
                    "type": "eventTypeCondition",
                    "parameterValues": {
                        "eventTypeId": "purchase"
                    }
                },
                {
                    "type": "eventPropertyCondition",
                    "parameterValues": {
                        "propertyName": "properties.totalAmount",
                        "comparisonOperator": "greaterThan",
                        "propertyValueInteger": 100
                    }
                }
            ]
        }
    },
    "actions": [
        {
            "type": "addToSegmentAction",
            "parameterValues": {
                "segmentId": "premium-users"
            }
        }
    ]
}
